198→    async fn identity_update(&self, params: Value) -> ServiceResult {
199→        let response = self
200→            .inner
201→            .identity_update(params)
202→            .map_err(ServiceError::message)?;
203→
204→        if let Some(state) = self.gateway_state.get()
205→            && let Some(location_value) = response.get("user_location")
206→        {
207→            let mut inner = state.inner.write().await;
208→            if location_value.is_null() {
209→                inner.cached_location = None;
210→            } else if let Some(location) = parse_geo_location(location_value) {
211→                inner.cached_location = Some(location);
212→            }
213→        }
214→
215→        Ok(response)
216→    }
