254→                    "memory_available": scan.memory_available,
255→                    "memory_files_count": scan.memory_files_count,
256→                    "channels_available": scan.channels_available,
257→                    "telegram_accounts": scan.telegram_accounts,
258→                    "discord_accounts": scan.discord_accounts,
259→                    "sessions_count": scan.sessions_count,
260→                    "unsupported_channels": scan.unsupported_channels,
261→                    "agent_ids": scan.agent_ids,
