290→    #[cfg(feature = "openclaw-import")]
291→    async fn openclaw_import(&self, params: Value) -> ServiceResult {
292→        let detection = moltis_openclaw_import::detect()
293→            .ok_or_else(|| "no OpenClaw installation found".to_string())?;
294→
295→        let selection = moltis_openclaw_import::ImportSelection {
296→            identity: params
297→                .get("identity")
298→                .and_then(|v| v.as_bool())
299→                .unwrap_or(false),
300→            providers: params
301→                .get("providers")
302→                .and_then(|v| v.as_bool())
303→                .unwrap_or(false),
304→            skills: params
305→                .get("skills")
306→                .and_then(|v| v.as_bool())
307→                .unwrap_or(false),
308→            memory: params
309→                .get("memory")
310→                .and_then(|v| v.as_bool())
311→                .unwrap_or(false),
312→            channels: params
313→                .get("channels")
314→                .and_then(|v| v.as_bool())
315→                .unwrap_or(false),
316→            sessions: params
317→                .get("sessions")
318→                .and_then(|v| v.as_bool())
319→                .unwrap_or(false),
320→            workspace_files: params
321→                .get("workspace_files")
322→                .and_then(|v| v.as_bool())
323→                .unwrap_or(false),
324→        };
325→
326→        let config_dir = moltis_config::config_dir()
327→            .ok_or_else(|| "could not determine config directory".to_string())?;
328→        let data_dir = moltis_config::data_dir();
329→
330→        let report = moltis_openclaw_import::import(&detection, &selection, &config_dir, &data_dir);
331→
332→        // Create imported agent personas (non-default agents)
333→        if let Some(ref agents) = report.imported_agents
334→            && let Err(e) = self.create_imported_agents(agents).await
335→        {
336→            tracing::warn!(error = %e, "openclaw import: failed to create imported agents");
337→        }
338→
339→        if selection.sessions
340→            && let Err(e) = self.sync_imported_sessions_to_sqlite(&data_dir).await
341→        {
342→            tracing::warn!(error = %e, "openclaw import: failed to sync sessions to sqlite metadata");
343→        }
344→
345→        // Ensure the default "main" session exists so it appears in the session
346→        // list alongside imported sessions. Without this, the main session only
347→        // gets created when the user sends their first message.
348→        if self.session_metadata.get("main").await.is_none()
349→            && let Err(e) = self
350→                .session_metadata
351→                .upsert("main", Some("Main".to_string()))
352→                .await
353→        {
354→            tracing::warn!(error = %e, "openclaw import: failed to ensure main session exists");
355→        }
356→
357→        Ok(serde_json::to_value(&report)?)
358→    }
359→
360→    #[cfg(not(feature = "openclaw-import"))]
361→    async fn openclaw_import(&self, _params: Value) -> ServiceResult {
362→        Err("openclaw import feature not enabled".into())
363→    }
364→}
