366→fn parse_geo_location(value: &Value) -> Option<moltis_config::GeoLocation> {
367→    let latitude = value.get("latitude").and_then(|v| v.as_f64())?;
368→    let longitude = value.get("longitude").and_then(|v| v.as_f64())?;
369→    let place = value
370→        .get("place")
371→        .and_then(|v| v.as_str())
372→        .map(|v| v.to_string());
373→    let updated_at = value.get("updated_at").and_then(|v| v.as_i64());
374→
375→    Some(moltis_config::GeoLocation {
376→        latitude,
377→        longitude,
378→        place,
379→        updated_at,
380→    })
381→}
