195→// ── Vault guard ─────────────────────────────────────────────────────────────
196→
197→/// Middleware that blocks API requests when the vault is sealed.
198→///
199→/// Returns 423 Locked for API endpoints (except auth and gon) when the vault
200→/// is in `Sealed` state. `Uninitialized` is not blocked — the vault doesn't
201→/// exist yet and there's nothing to protect.
202→#[cfg(feature = "vault")]
203→pub async fn vault_guard(
204→    State(state): State<super::server::AppState>,
205→    request: axum::http::Request<axum::body::Body>,
206→    next: Next,
207→) -> axum::response::Response {
208→    let Some(ref vault) = state.gateway.vault else {
209→        return next.run(request).await;
210→    };
211→    let path = request.uri().path();
212→    // Allow auth, public, gon, and non-API routes through.
213→    if !path.starts_with("/api/")
214→        || path.starts_with("/api/auth/")
215→        || path.starts_with("/api/public/")
216→        || path == "/api/gon"
217→    {
218→        return next.run(request).await;
219→    }
220→    // Only block when Sealed (not Uninitialized).
221→    if matches!(vault.status().await, Ok(moltis_vault::VaultStatus::Sealed)) {
222→        return (
223→            StatusCode::LOCKED,
224→            Json(serde_json::json!({"error": "vault is sealed", "status": "sealed"})),
225→        )
226→            .into_response();
227→    }
228→    next.run(request).await
229→}
