231→// ── AuthSession extractor ───────────────────────────────────────────────────
232→
233→/// Axum extractor that validates the session cookie and produces an
234→/// `AuthIdentity`. Returns 401 if the session is missing or invalid.
235→///
236→/// When `auth_gate` has already run, it reads the [`AuthIdentity`] the
237→/// middleware inserted into extensions. For auth routes (on the public
238→/// allowlist, where `auth_gate` skips auth), it falls back to validating
239→/// the session cookie directly.
240→pub struct AuthSession(pub AuthIdentity);
241→
242→impl<S> FromRequestParts<S> for AuthSession
243→where
244→    S: Send + Sync,
245→    Arc<CredentialStore>: FromRef<S>,
246→    Arc<GatewayState>: FromRef<S>,
247→{
248→    type Rejection = (StatusCode, &'static str);
249→
250→    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
251→        // If auth_gate already ran and set identity, use it.
252→        if let Some(id) = parts.extensions.get::<AuthIdentity>() {
253→            return Ok(AuthSession(id.clone()));
254→        }
255→
256→        // Fallback for auth routes (allowlisted, middleware skipped):
257→        // validate session cookie directly, or check the local-bypass logic.
258→        let store = Arc::<CredentialStore>::from_ref(state);
259→        let gw = Arc::<GatewayState>::from_ref(state);
260→
261→        let is_local = parts
262→            .extensions
263→            .get::<ConnectInfo<SocketAddr>>()
264→            .is_some_and(|ci| is_local_connection(&parts.headers, ci.0, gw.behind_proxy));
265→
266→        match check_auth(&store, &parts.headers, is_local).await {
267→            AuthResult::Allowed(identity) => Ok(AuthSession(identity)),
268→            _ => Err((StatusCode::UNAUTHORIZED, "not authenticated")),
269→        }
270→    }
271→}
