273→// ── Helpers ─────────────────────────────────────────────────────────────────
274→
275→/// Extract the Cookie header value.
276→fn cookie_header(headers: &HeaderMap) -> Option<&str> {
277→    headers
278→        .get(axum::http::header::COOKIE)
279→        .and_then(|v| v.to_str().ok())
280→}
281→
282→/// Extract a Bearer token from the Authorization header.
283→fn bearer_token(headers: &HeaderMap) -> Option<&str> {
284→    headers
285→        .get(axum::http::header::AUTHORIZATION)
286→        .and_then(|v| v.to_str().ok())
287→        .and_then(|v| v.strip_prefix("Bearer "))
288→}
289→
290→/// Parse a specific cookie value from a Cookie header string.
291→pub fn parse_cookie<'a>(header: &'a str, name: &str) -> Option<&'a str> {
292→    for part in header.split(';') {
293→        let part = part.trim();
294→        if let Some(value) = part.strip_prefix(name)
295→            && let Some(value) = value.strip_prefix('=')
296→        {
297→            return Some(value);
298→        }
299→    }
300→    None
301→}
