  1→//! Connection locality detection for auth decisions.
  2→//!
  3→//! Determines whether a request is a direct local connection (no proxy)
  4→//! based on headers, remote address, and proxy configuration.
  5→
  6→use std::net::SocketAddr;
  7→
  8→/// Returns `true` when common proxy/forwarding headers are present.
  9→pub fn has_proxy_headers(headers: &axum::http::HeaderMap) -> bool {
 10→    headers.contains_key("x-forwarded-for")
 11→        || headers.contains_key("x-real-ip")
 12→        || headers.contains_key("cf-connecting-ip")
 13→        || headers.get("forwarded").is_some()
 14→}
 15→
 16→/// Returns `true` when `host` (without port) is a loopback name/address.
 17→fn is_loopback_host(host: &str) -> bool {
 18→    // Strip port (IPv6 bracket form, bare IPv6, or simple host:port).
 19→    let name = if host.starts_with('[') {
 20→        // [::1]:port or [::1]
 21→        host.rsplit_once("]:")
 22→            .map_or(host, |(addr, _)| addr)
 23→            .trim_start_matches('[')
 24→            .trim_end_matches(']')
 25→    } else if host.matches(':').count() > 1 {
 26→        // Bare IPv6 like ::1 (multiple colons, no brackets) — no port stripping.
 27→        host
 28→    } else {
 29→        host.rsplit_once(':').map_or(host, |(addr, _)| addr)
 30→    };
 31→    matches!(name, "localhost" | "127.0.0.1" | "::1") || name.ends_with(".localhost")
 32→}
 33→
 34→/// Determine whether a connection is a **direct local** connection (no proxy
 35→/// in between).
 36→///
 37→/// When `behind_proxy` is `true`, the caller is known to be behind a reverse
 38→/// proxy, so loopback source IPs are never treated as proof of a direct local
 39→/// connection.
 40→pub fn is_local_connection(
 41→    headers: &axum::http::HeaderMap,
 42→    remote_addr: SocketAddr,
 43→    behind_proxy: bool,
 44→) -> bool {
 45→    // Hard override: env var says we're behind a proxy.
 46→    if behind_proxy {
 47→        return false;
 48→    }
 49→
 50→    // Proxy headers present → proxied traffic.
 51→    if has_proxy_headers(headers) {
 52→        return false;
 53→    }
 54→
 55→    // Host header points to a non-loopback name → likely proxied.
 56→    if let Some(host) = headers
 57→        .get(axum::http::header::HOST)
 58→        .and_then(|v| v.to_str().ok())
 59→        && !is_loopback_host(host)
 60→    {
 61→        return false;
 62→    }
 63→
 64→    // TCP source must be loopback.
 65→    remote_addr.ip().is_loopback()
 66→}
