 1→//! Terminal-based onboarding wizard using the shared state machine.
 2→
 3→use std::io::{BufRead, Write};
 4→
 5→use moltis_config::{MoltisConfig, find_or_default_config_path, save_config};
 6→
 7→use crate::{Context, Result, state::WizardState};
 8→
 9→/// Run the interactive onboarding wizard in the terminal.
10→pub async fn run_onboarding() -> Result<()> {
11→    let config_path = find_or_default_config_path();
12→
13→    // Check if already onboarded.
14→    let mut identity_name: Option<String> = None;
15→    let mut user_name: Option<String> = None;
16→    if config_path.exists()
17→        && let Ok(cfg) = moltis_config::loader::load_config(&config_path)
18→    {
19→        identity_name = cfg.identity.name;
20→        user_name = cfg.user.name;
21→    }
22→    if let Some(id) = moltis_config::load_identity()
23→        && id.name.is_some()
24→    {
25→        identity_name = id.name;
26→    }
27→    if let Some(user) = moltis_config::load_user()
28→        && user.name.is_some()
29→    {
30→        user_name = user.name;
31→    }
32→
33→    if identity_name.is_some() && user_name.is_some() {
34→        println!(
35→            "Already onboarded as {} with agent {}.",
36→            user_name.as_deref().unwrap_or("?"),
37→            identity_name.as_deref().unwrap_or("?"),
38→        );
39→        return Ok(());
40→    }
41→
42→    let mut state = WizardState::new();
43→    let stdin = std::io::stdin();
44→    let mut reader = stdin.lock();
45→
46→    while !state.is_done() {
47→        println!("{}", state.prompt());
48→        print!("> ");
49→        std::io::stdout().flush()?;
50→        let mut line = String::new();
51→        reader.read_line(&mut line)?;
52→        state.advance(&line);
53→    }
54→
55→    // Merge into existing config or create new one.
56→    let mut config = if config_path.exists() {
57→        moltis_config::loader::load_config(&config_path).unwrap_or_default()
58→    } else {
59→        MoltisConfig::default()
60→    };
61→    config.identity = state.identity;
62→    config.user = state.user;
63→
64→    let path = save_config(&config).context("failed to save onboarding config")?;
65→    moltis_config::save_identity(&config.identity).context("failed to save identity")?;
66→    moltis_config::save_user(&config.user).context("failed to save user")?;
67→    println!("Config saved to {}", path.display());
68→    println!("Onboarding complete!");
69→    Ok(())
70→}
