  1→//! Pure state machine for the onboarding wizard. No I/O.
  2→
  3→use moltis_config::{AgentIdentity, UserProfile};
  4→
  5→/// Steps in the onboarding wizard.
  6→#[derive(Debug, Clone, Copy, PartialEq, Eq, serde::Serialize)]
  7→#[serde(rename_all = "snake_case")]
  8→pub enum WizardStep {
  9→    Welcome,
 10→    UserName,
 11→    AgentName,
 12→    AgentEmoji,
 13→    AgentTheme,
 14→    Confirm,
 15→    Done,
 16→}
 17→
 18→/// The wizard state, advanced one step at a time.
 19→#[derive(Debug, Clone)]
 20→pub struct WizardState {
 21→    pub step: WizardStep,
 22→    pub user: UserProfile,
 23→    pub identity: AgentIdentity,
 24→}
 25→
 26→impl Default for WizardState {
 27→    fn default() -> Self {
 28→        Self::new()
 29→    }
 30→}
 31→
 32→impl WizardState {
 33→    pub fn new() -> Self {
 34→        Self {
 35→            step: WizardStep::Welcome,
 36→            user: UserProfile::default(),
 37→            identity: AgentIdentity::default(),
 38→        }
 39→    }
 40→
 41→    /// The prompt text to display for the current step.
 42→    pub fn prompt(&self) -> &str {
 43→        match self.step {
 44→            WizardStep::Welcome => {
 45→                "Welcome to moltis! Let's set things up. Press Enter to continue."
 46→            },
 47→            WizardStep::UserName => "What's your name?",
 48→            WizardStep::AgentName => "Pick a name for your agent:",
 49→            WizardStep::AgentEmoji => "Choose an emoji for your agent (e.g. \u{1f916}):",
 50→            WizardStep::AgentTheme => {
 51→                "Describe your agent's theme (e.g. wise owl, chill fox, witty robot):"
 52→            },
 53→            WizardStep::Confirm => "All set! Press Enter to save, or type 'back' to go back.",
 54→            WizardStep::Done => "Onboarding complete!",
 55→        }
 56→    }
 57→
 58→    /// Process user input and advance to the next step.
 59→    pub fn advance(&mut self, input: &str) {
 60→        let input = input.trim();
 61→        match self.step {
 62→            WizardStep::Welcome => self.step = WizardStep::UserName,
 63→            WizardStep::UserName => {
 64→                if !input.is_empty() {
 65→                    self.user.name = Some(input.to_string());
 66→                }
 67→                self.step = WizardStep::AgentName;
 68→            },
 69→            WizardStep::AgentName => {
 70→                if !input.is_empty() {
 71→                    self.identity.name = Some(input.to_string());
 72→                } else if self.identity.name.is_none() {
 73→                    self.identity.name = Some("moltis".to_string());
 74→                }
 75→                self.step = WizardStep::AgentEmoji;
 76→            },
 77→            WizardStep::AgentEmoji => {
 78→                if !input.is_empty() {
 79→                    self.identity.emoji = Some(input.to_string());
 80→                }
 81→                self.step = WizardStep::AgentTheme;
 82→            },
 83→            WizardStep::AgentTheme => {
 84→                if !input.is_empty() {
 85→                    self.identity.theme = Some(input.to_string());
 86→                }
 87→                self.step = WizardStep::Confirm;
 88→            },
 89→            WizardStep::Confirm => {
 90→                if input.eq_ignore_ascii_case("back") {
 91→                    self.step = WizardStep::AgentTheme;
 92→                } else {
 93→                    self.step = WizardStep::Done;
 94→                }
 95→            },
 96→            WizardStep::Done => {},
 97→        }
 98→    }
 99→
100→    pub fn is_done(&self) -> bool {
101→        self.step == WizardStep::Done
102→    }
103→}
104→
105→#[cfg(test)]
106→mod tests {
107→    use super::*;
108→
109→    #[test]
110→    fn full_wizard_flow() {
111→        let mut s = WizardState::new();
112→        assert_eq!(s.step, WizardStep::Welcome);
113→
114→        s.advance(""); // welcome → user name
115→        assert_eq!(s.step, WizardStep::UserName);
116→
117→        s.advance("Alice"); // → agent name
118→        assert_eq!(s.user.name.as_deref(), Some("Alice"));
119→        assert_eq!(s.step, WizardStep::AgentName);
120→
121→        s.advance("Momo"); // → emoji
122→        assert_eq!(s.identity.name.as_deref(), Some("Momo"));
123→
124→        s.advance("\u{1f99c}"); // → theme
125→        assert_eq!(s.identity.emoji.as_deref(), Some("\u{1f99c}"));
126→
127→        s.advance("cheerful parrot"); // → confirm
128→        assert_eq!(s.identity.theme.as_deref(), Some("cheerful parrot"));
129→        assert_eq!(s.step, WizardStep::Confirm);
130→
131→        s.advance(""); // confirm → done
132→        assert!(s.is_done());
133→    }
134→
135→    #[test]
136→    fn back_from_confirm() {
137→        let mut s = WizardState::new();
138→        // fast-forward to confirm
139→        s.advance(""); // welcome
140→        s.advance("Bob");
141→        s.advance("Rex");
142→        s.advance("\u{1f436}");
143→        s.advance("loyal dog");
144→        assert_eq!(s.step, WizardStep::Confirm);
145→
146→        s.advance("back");
147→        assert_eq!(s.step, WizardStep::AgentTheme);
148→    }
149→
150→    #[test]
151→    fn default_agent_name() {
152→        let mut s = WizardState::new();
153→        s.advance(""); // welcome
154→        s.advance("User");
155→        s.advance(""); // empty agent name → defaults to "moltis"
156→        assert_eq!(s.identity.name.as_deref(), Some("moltis"));
157→    }
158→}
