  1→//! Live onboarding service that backs the `wizard.*` RPC methods.
  2→
  3→use std::{path::PathBuf, sync::Mutex};
  4→
  5→use {
  6→    serde_json::{Value, json},
  7→    tracing::info,
  8→};
  9→
 10→use moltis_config::{AgentIdentity, MoltisConfig, UserProfile};
 11→
 12→use crate::{
 13→    Context, Result,
 14→    state::{WizardState, WizardStep},
 15→};
 16→
 17→/// Live onboarding service backed by a `WizardState` and config persistence.
 18→pub struct LiveOnboardingService {
 19→    state: Mutex<Option<WizardState>>,
 20→    config_path: PathBuf,
 21→}
 22→
 23→impl LiveOnboardingService {
 24→    pub fn new(config_path: PathBuf) -> Self {
 25→        Self {
 26→            state: Mutex::new(None),
 27→            config_path,
 28→        }
 29→    }
 30→
 31→    /// Save config to the service's config path.
 32→    fn save(&self, config: &MoltisConfig) -> Result<()> {
 33→        moltis_config::loader::save_config_to_path(&self.config_path, config)
 34→            .context("failed to save onboarding config")?;
 35→        Ok(())
 36→    }
 37→
 38→    /// Check whether onboarding has been completed.
 39→    ///
 40→    /// Returns `true` when the `.onboarded` sentinel file exists in the data
 41→    /// directory (written after the wizard finishes) **or** the
 42→    /// `SKIP_ONBOARDING` environment variable is set to a non-empty value.
 43→    /// Pre-existing identity/user data alone no longer auto-skips.
 44→    fn is_already_onboarded(&self) -> bool {
 45→        if std::env::var("SKIP_ONBOARDING")
 46→            .ok()
 47→            .is_some_and(|v| !v.is_empty())
 48→        {
 49→            return true;
 50→        }
 51→        onboarded_sentinel().exists()
 52→    }
 53→
 54→    /// Mark onboarding as complete by writing the sentinel file.
 55→    fn mark_onboarded(&self) {
 56→        let path = onboarded_sentinel();
 57→        let _ = std::fs::write(&path, "");
 58→    }
 59→
 60→    /// Start the wizard. Returns current step info.
 61→    ///
 62→    /// If `force` is true, the wizard starts even when already onboarded,
 63→    /// allowing the user to reconfigure their identity.
 64→    pub fn wizard_start(&self, force: bool) -> Value {
 65→        if !force && self.is_already_onboarded() {
 66→            return json!({
 67→                "onboarded": true,
 68→                "step": "done",
 69→                "prompt": "Already onboarded!",
 70→            });
 71→        }
 72→
 73→        let mut ws = WizardState::new();
 74→
 75→        // Pre-populate from existing config so the user can keep values.
 76→        if self.config_path.exists()
 77→            && let Ok(cfg) = moltis_config::loader::load_config(&self.config_path)
 78→        {
 79→            ws.identity = cfg.identity;
 80→            ws.user = cfg.user;
 81→        }
 82→        if let Some(file_identity) = moltis_config::load_identity() {
 83→            merge_identity(&mut ws.identity, &file_identity);
 84→        }
 85→        if let Some(file_user) = moltis_config::load_user() {
 86→            merge_user(&mut ws.user, &file_user);
 87→        }
 88→
 89→        let resp = step_response(&ws);
 90→        *self.state.lock().unwrap_or_else(|e| e.into_inner()) = Some(ws);
 91→        resp
 92→    }
 93→
 94→    /// Advance the wizard with user input.
 95→    pub fn wizard_next(&self, input: &str) -> Result<Value> {
 96→        let mut guard = self.state.lock().unwrap_or_else(|e| e.into_inner());
 97→        let ws = guard.as_mut().context("no active wizard session")?;
 98→        ws.advance(input);
 99→
100→        if ws.is_done() {
101→            // Merge into existing config or create new one.
102→            let mut config = if self.config_path.exists() {
103→                moltis_config::loader::load_config(&self.config_path).unwrap_or_default()
104→            } else {
105→                MoltisConfig::default()
106→            };
107→            config.identity = ws.identity.clone();
108→            config.user = ws.user.clone();
109→            self.save(&config).context("failed to save config")?;
110→            moltis_config::save_identity(&ws.identity).context("failed to save IDENTITY.md")?;
111→            moltis_config::save_user(&ws.user).context("failed to save USER.md")?;
112→            self.mark_onboarded();
113→
114→            let resp = json!({
115→                "step": "done",
116→                "prompt": ws.prompt(),
117→                "done": true,
118→                "identity": {
119→                    "name": config.identity.name,
120→                    "emoji": config.identity.emoji,
121→                    "theme": config.identity.theme,
122→                },
123→                "user": {
124→                    "name": config.user.name,
125→                    "timezone": config.user.timezone,
126→                },
127→            });
128→            *guard = None;
129→            return Ok(resp);
130→        }
131→
132→        Ok(step_response(ws))
133→    }
134→
135→    /// Cancel an active wizard session.
136→    pub fn wizard_cancel(&self) {
137→        *self.state.lock().unwrap_or_else(|e| e.into_inner()) = None;
138→    }
139→
140→    /// Return the current wizard status.
141→    pub fn wizard_status(&self) -> Value {
142→        let guard = self.state.lock().unwrap_or_else(|e| e.into_inner());
143→        let onboarded = self.is_already_onboarded();
144→        match guard.as_ref() {
145→            Some(ws) => json!({
146→                "active": true,
147→                "step": ws.step,
148→                "onboarded": onboarded,
149→            }),
150→            None => json!({
151→                "active": false,
152→                "onboarded": onboarded,
153→            }),
154→        }
155→    }
156→
157→    /// Update identity fields by merging partial JSON into the existing config.
158→    ///
159→    /// Accepts: `{name?, emoji?, theme?, soul?, user_name?, user_timezone?}`
160→    /// Also accepts `"creature"` and `"vibe"` as backward-compat aliases for `"theme"`.
161→    pub fn identity_update(&self, params: Value) -> Result<Value> {
162→        let mut config = if self.config_path.exists() {
163→            moltis_config::loader::load_config(&self.config_path).unwrap_or_default()
164→        } else {
165→            MoltisConfig::default()
166→        };
167→        let mut identity = config.identity.clone();
168→        if let Some(file_identity) = moltis_config::load_identity() {
169→            merge_identity(&mut identity, &file_identity);
170→        }
171→        let mut user = config.user.clone();
172→        if let Some(file_user) = moltis_config::load_user() {
173→            merge_user(&mut user, &file_user);
174→        }
175→
176→        /// Extract an optional non-empty string from JSON, mapping `""` to `None`.
177→        fn str_field(params: &Value, key: &str) -> Option<Option<String>> {
178→            params
179→                .get(key)
180→                .and_then(|v| v.as_str())
181→                .map(|v| (!v.is_empty()).then(|| v.to_string()))
182→        }
183→
184→        /// Extract optional timezone field, mapping:
185→        /// - missing key => None (no-op)
186→        /// - empty string => Some(None) (clear timezone)
187→        /// - valid IANA timezone => Some(Some(Timezone))
188→        /// - invalid timezone => None (ignore)
189→        fn timezone_field(params: &Value, key: &str) -> Option<Option<moltis_config::Timezone>> {
190→            let raw = params.get(key).and_then(|v| v.as_str())?;
191→            let trimmed = raw.trim();
192→            if trimmed.is_empty() {
193→                return Some(None);
194→            }
195→            trimmed.parse::<moltis_config::Timezone>().ok().map(Some)
196→        }
197→
198→        /// Extract optional location field from either `user_location` or `location`.
199→        ///
200→        /// Accepted shape:
201→        /// `{ latitude: f64, longitude: f64, place?: String }`.
202→        /// - Missing key => None (no-op)
203→        /// - null => Some(None) (clear location)
204→        /// - invalid payload => None (ignore)
205→        fn location_field(params: &Value) -> Option<Option<moltis_config::GeoLocation>> {
206→            let raw = params
207→                .get("user_location")
208→                .or_else(|| params.get("location"))?;
209→
210→            if raw.is_null() {
211→                return Some(None);
212→            }
213→
214→            let latitude = raw.get("latitude").and_then(|v| v.as_f64())?;
215→            let longitude = raw.get("longitude").and_then(|v| v.as_f64())?;
216→            let place = raw
217→                .get("place")
218→                .and_then(|v| v.as_str())
219→                .map(|v| v.to_string());
220→
221→            Some(Some(moltis_config::GeoLocation::now(
222→                latitude, longitude, place,
223→            )))
224→        }
225→
226→        if let Some(v) = str_field(&params, "name") {
227→            identity.name = v;
228→        }
229→        if let Some(v) = str_field(&params, "emoji") {
230→            identity.emoji = v;
231→        }
232→        if let Some(v) = str_field(&params, "theme") {
233→            identity.theme = v;
234→        }
235→        // Backward compat: accept creature/vibe and compose into theme.
236→        if let Some(creature) = str_field(&params, "creature") {
237→            let vibe = str_field(&params, "vibe").flatten();
238→            identity.theme = match (vibe, creature) {
239→                (Some(v), Some(c)) => Some(format!("{v} {c}")),
240→                (Some(v), None) => Some(v),
241→                (None, Some(c)) => Some(c),
242→                (None, None) => None,
243→            };
244→        } else if let Some(vibe) = str_field(&params, "vibe") {
245→            identity.theme = vibe;
246→        }
247→        if let Some(v) = params.get("soul") {
248→            let soul = if v.is_null() {
249→                None
250→            } else {
251→                v.as_str().map(|s| s.to_string())
252→            };
253→            moltis_config::save_soul(soul.as_deref()).context("failed to save soul")?;
254→        }
255→        if let Some(v) = str_field(&params, "user_name") {
256→            user.name = v;
257→        }
258→        if let Some(v) =
259→            timezone_field(&params, "user_timezone").or_else(|| timezone_field(&params, "timezone"))
260→        {
261→            user.timezone = v;
262→        }
263→        if let Some(v) = location_field(&params) {
264→            user.location = v;
265→        }
266→
267→        config.identity = identity.clone();
268→        config.user = user.clone();
269→
270→        self.save(&config)?;
271→        moltis_config::save_identity(&identity).context("failed to save identity")?;
272→        moltis_config::save_user(&user).context("failed to save user")?;
273→
274→        // Mark onboarding complete once both names are present.
275→        if identity.name.is_some() && user.name.is_some() {
276→            self.mark_onboarded();
277→        }
278→
279→        Ok(json!({
280→            "name": identity.name,
281→            "emoji": identity.emoji,
282→            "theme": identity.theme,
283→            "soul": moltis_config::load_soul(),
284→            "user_name": user.name,
285→            "user_timezone": user.timezone.as_ref().map(|tz| tz.name()),
286→            "user_location": user.location.as_ref().map(|loc| json!({
287→                "latitude": loc.latitude,
288→                "longitude": loc.longitude,
289→                "place": loc.place,
290→                "updated_at": loc.updated_at,
291→            })),
292→        }))
293→    }
294→
295→    /// Update SOUL.md in the workspace root.
296→    pub fn identity_update_soul(&self, soul: Option<String>) -> Result<Value> {
297→        moltis_config::save_soul(soul.as_deref()).context("failed to save soul")?;
298→        Ok(json!({}))
299→    }
300→
301→    /// Read identity from the config file (for `agent.identity.get`).
302→    pub fn identity_get(&self) -> moltis_config::ResolvedIdentity {
303→        let id = if self.config_path.exists()
304→            && let Ok(cfg) = moltis_config::loader::load_config(&self.config_path)
305→        {
306→            info!(
307→                config_path = %self.config_path.display(),
308→                config_name = ?cfg.identity.name,
309→                config_theme = ?cfg.identity.theme,
310→                "identity_get: loaded config"
311→            );
312→            moltis_config::resolve_identity_from_config(&cfg)
313→        } else {
314→            info!(
315→                config_path = %self.config_path.display(),
316→                "identity_get: config not found, using defaults"
317→            );
318→            moltis_config::resolve_identity_from_config(&MoltisConfig::default())
319→        };
320→        info!(
321→            resolved_name = %id.name,
322→            resolved_emoji = ?id.emoji,
323→            resolved_theme = ?id.theme,
324→            resolved_user_name = ?id.user_name,
325→            "identity_get: resolved identity"
326→        );
327→        id
328→    }
329→}
330→
331→/// Path to the `.onboarded` sentinel file in the data directory.
332→fn onboarded_sentinel() -> PathBuf {
333→    moltis_config::data_dir().join(".onboarded")
334→}
335→
336→fn merge_identity(dst: &mut AgentIdentity, src: &AgentIdentity) {
337→    if src.name.is_some() {
338→        dst.name = src.name.clone();
339→    }
340→    if src.emoji.is_some() {
341→        dst.emoji = src.emoji.clone();
342→    }
343→    if src.theme.is_some() {
344→        dst.theme = src.theme.clone();
345→    }
346→}
347→
348→fn merge_user(dst: &mut UserProfile, src: &UserProfile) {
349→    if src.name.is_some() {
350→        dst.name = src.name.clone();
351→    }
352→    if src.timezone.is_some() {
353→        dst.timezone = src.timezone.clone();
354→    }
355→    if src.location.is_some() {
356→        dst.location = src.location.clone();
357→    }
358→}
359→
360→fn step_response(ws: &WizardState) -> Value {
361→    json!({
362→        "step": ws.step,
363→        "prompt": ws.prompt(),
364→        "done": ws.step == WizardStep::Done,
365→        "onboarded": false,
366→        "current": current_value(ws),
367→    })
368→}
369→
370→/// Returns the current (pre-populated) value for the active step, if any.
371→fn current_value(ws: &WizardState) -> Option<&str> {
372→    use WizardStep::*;
373→    match ws.step {
374→        UserName => ws.user.name.as_deref(),
375→        AgentName => ws.identity.name.as_deref(),
376→        AgentEmoji => ws.identity.emoji.as_deref(),
377→        AgentTheme => ws.identity.theme.as_deref(),
378→        _ => None,
379→    }
380→}
