132→// ── Auth step ───────────────────────────────────────────────
133→
134→// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: auth step handles passkey+password+code flows
135→function AuthStep({ onNext, skippable }) {
136→	var [method, setMethod] = useState(null); // null | "passkey" | "password"
137→	var [password, setPassword] = useState("");
138→	var [confirm, setConfirm] = useState("");
139→	var [setupCode, setSetupCode] = useState("");
140→	var [passkeyName, setPasskeyName] = useState("");
141→	var [codeRequired, setCodeRequired] = useState(false);
142→	var [localhostOnly, setLocalhostOnly] = useState(false);
143→	var [webauthnAvailable, setWebauthnAvailable] = useState(false);
144→	var [error, setError] = useState(null);
145→	var [saving, setSaving] = useState(false);
146→	var [loading, setLoading] = useState(true);
147→	var [passkeyOrigins, setPasskeyOrigins] = useState([]);
148→	var [passkeyDone, setPasskeyDone] = useState(false);
149→	var [optPw, setOptPw] = useState("");
150→	var [optPwConfirm, setOptPwConfirm] = useState("");
151→	var [optPwSaving, setOptPwSaving] = useState(false);
152→	var [recoveryKey, setRecoveryKey] = useState(null);
153→	var [recoveryCopied, setRecoveryCopied] = useState(false);
154→
155→	var isIpAddress = /^\d+\.\d+\.\d+\.\d+$/.test(location.hostname) || location.hostname.startsWith("[");
156→	var browserSupportsWebauthn = !!window.PublicKeyCredential;
157→	var passkeyEnabled = webauthnAvailable && browserSupportsWebauthn && !isIpAddress;
158→
159→	var [setupComplete, setSetupComplete] = useState(false);
160→
161→	useEffect(() => {
162→		fetch("/api/auth/status")
163→			.then((r) => r.json())
164→			.then((data) => {
165→				if (data.setup_code_required) setCodeRequired(true);
166→				if (data.localhost_only) setLocalhostOnly(true);
167→				if (data.webauthn_available) setWebauthnAvailable(true);
168→				if (data.passkey_origins) setPasskeyOrigins(data.passkey_origins);
169→				if (data.setup_complete) setSetupComplete(true);
170→				setLoading(false);
171→			})
172→			.catch(() => setLoading(false));
173→	}, []);
174→
175→	// Pre-select passkey when available (easier than passwords)
176→	useEffect(() => {
177→		if (passkeyEnabled && method === null) setMethod("passkey");
178→	}, [passkeyEnabled]);
179→
180→	// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: password+code validation
181→	function onPasswordSubmit(e) {
182→		e.preventDefault();
183→		setError(null);
184→		if (password.length > 0 || !localhostOnly) {
185→			if (password.length < 8) {
186→				setError("Password must be at least 8 characters.");
187→				return;
188→			}
189→			if (password !== confirm) {
190→				setError("Passwords do not match.");
191→				return;
192→			}
193→		}
194→		if (codeRequired && setupCode.trim().length === 0) {
195→			setError("Enter the setup code shown in the process log (stdout).");
196→			return;
197→		}
198→		setSaving(true);
199→		var body = password ? { password } : {};
200→		if (codeRequired) body.setup_code = setupCode.trim();
201→		fetch("/api/auth/setup", {
202→			method: "POST",
203→			headers: { "Content-Type": "application/json" },
204→			body: JSON.stringify(body),
205→		})
206→			.then((r) => {
207→				if (r.ok) {
208→					ensureWsConnected();
209→					return r
210→						.json()
211→						.then((data) => {
212→							if (data.recovery_key) {
213→								setRecoveryKey(data.recovery_key);
214→								setSaving(false);
215→							} else {
216→								onNext();
217→							}
218→						})
219→						.catch(() => onNext());
220→				} else {
221→					return r.text().then((t) => {
222→						setError(t || "Setup failed");
223→						setSaving(false);
224→					});
225→				}
226→			})
227→			.catch((err) => {
228→				setError(err.message);
229→				setSaving(false);
230→			});
231→	}
232→
233→	function onPasskeyRegister() {
234→		setError(null);
235→		if (codeRequired && setupCode.trim().length === 0) {
236→			setError("Enter the setup code shown in the process log (stdout).");
237→			return;
238→		}
239→		setSaving(true);
240→		var codeBody = codeRequired ? { setup_code: setupCode.trim() } : {};
241→		var requestedRpId = null;
242→		fetch("/api/auth/setup/passkey/register/begin", {
243→			method: "POST",
244→			headers: { "Content-Type": "application/json" },
245→			body: JSON.stringify(codeBody),
246→		})
247→			.then((r) => {
248→				if (!r.ok) return r.text().then((t) => Promise.reject(new Error(t || "Failed to start passkey registration")));
249→				return r.json();
250→			})
251→			.then((data) => {
252→				var options = data.options;
253→				requestedRpId = options.publicKey.rp?.id || null;
254→				options.publicKey.challenge = base64ToBuffer(options.publicKey.challenge);
255→				options.publicKey.user.id = base64ToBuffer(options.publicKey.user.id);
256→				if (options.publicKey.excludeCredentials) {
257→					for (var c of options.publicKey.excludeCredentials) {
258→						c.id = base64ToBuffer(c.id);
259→					}
260→				}
261→				return navigator.credentials
262→					.create({ publicKey: options.publicKey })
263→					.then((cred) => ({ cred, challengeId: data.challenge_id }));
264→			})
265→			.then(({ cred, challengeId }) => {
266→				var body = {
267→					challenge_id: challengeId,
268→					name: passkeyName.trim() || detectPasskeyName(cred),
269→					credential: {
270→						id: cred.id,
271→						rawId: bufferToBase64(cred.rawId),
272→						type: cred.type,
273→						response: {
274→							attestationObject: bufferToBase64(cred.response.attestationObject),
275→							clientDataJSON: bufferToBase64(cred.response.clientDataJSON),
276→						},
277→					},
278→				};
279→				if (codeRequired) body.setup_code = setupCode.trim();
280→				return fetch("/api/auth/setup/passkey/register/finish", {
281→					method: "POST",
282→					headers: { "Content-Type": "application/json" },
283→					body: JSON.stringify(body),
284→				});
