 20→async function detectOnboardingStep(page) {
 21→	const pathname = new URL(page.url()).pathname;
 22→	if (/^\/chats\//.test(pathname)) return "chats";
 23→
 24→	const currentHeading = page.locator(".onboarding-card h2").first();
 25→	if (!(await isVisible(currentHeading))) return "pending";
 26→	const headingText = ((await currentHeading.textContent()) || "").trim();
 27→
 28→	if (headingText === "Secure your instance") return "auth";
 29→	if (headingText === "Set up your identity") return "identity";
 30→	if (/^(Add LLMs|Add providers)$/.test(headingText)) return "providers";
 31→	if (headingText === "Voice (optional)") return "voice";
 32→	if (headingText === "Connect a Channel") return "channel";
 33→	if (headingText === "Setup Summary") return "summary";
 34→	return "pending";
 35→}
