 42→async function advanceToIdentityStep(page) {
 43→	for (let i = 0; i < 6; i++) {
 44→		const step = await detectOnboardingStep(page);
 45→		if (step === "identity" || step === "chats" || step === "summary") return step;
 46→		if (step === "auth") {
 47→			await completePasswordAuthStep(page);
 48→			continue;
 49→		}
 50→		if (step === "providers" || step === "voice" || step === "channel") {
 51→			if (await clickFirstVisibleButton(page, { name: /skip for now/i })) continue;
 52→			if (await clickFirstVisibleButton(page, { name: /continue/i })) continue;
 53→		}
 54→		break;
 55→	}
 56→	return detectOnboardingStep(page);
