 23→/// Session cookie name.
 24→pub const SESSION_COOKIE: &str = "moltis_session";
 25→const AUTH_SETUP_REQUIRED: &str = "AUTH_SETUP_REQUIRED";
 26→const AUTH_NOT_AUTHENTICATED: &str = "AUTH_NOT_AUTHENTICATED";
