149→                next.run(request).await
150→            }
151→        },
152→        AuthResult::Unauthorized => {
153→            if path.starts_with("/api/") || path.starts_with("/ws/") {
154→                if path.starts_with("/ws/") {
155→                    let has_bearer = bearer_token(request.headers()).is_some();
