159→                        path,
160→                        remote = %addr,
161→                        is_local,
162→                        has_bearer,
163→                        has_session_cookie,
164→                        "auth reject: unauthorized websocket connection"
165→                    );
166→                }
167→                (
168→                    StatusCode::UNAUTHORIZED,
169→                    Json(serde_json::json!({
170→                        "code": AUTH_NOT_AUTHENTICATED,
171→                        "error": "not authenticated"
172→                    })),
173→                )
174→                    .into_response()
175→            } else {
176→                Redirect::to("/login").into_response()
177→            }
178→        },
179→    }
180→}
