							sysInfo.isAppleSilicon && (sysInfo.availableBackends || []).length > 0
								? html`<div class="flex flex-col gap-2">
								<div class="text-xs font-medium text-[var(--text-strong)]">Backend</div>
								<div class="flex flex-col gap-2">
