function discordInviteUrl(token) {
	if (!token) return "";
	var parts = token.split(".");
	if (parts.length < 3) return "";
	try {
		var id = atob(parts[0]);
		if (!/^\d+$/.test(id)) return "";
		return `https://discord.com/oauth2/authorize?client_id=${id}&scope=bot&permissions=100352`;
	} catch {
		return "";
	}
}

