 1→//! SPA fallback, onboarding redirect, and login page handlers.
 2→
 3→use {
 4→    axum::{
 5→        extract::State,
 6→        http::{StatusCode, Uri},
 7→        response::{IntoResponse, Redirect},
 8→    },
 9→    moltis_gateway::server::AppState,
10→};
11→
12→use crate::templates::{
13→    SpaTemplate, onboarding_completed, render_spa_template, should_redirect_from_onboarding,
14→    should_redirect_to_onboarding,
15→};
16→
17→pub async fn spa_fallback(State(state): State<AppState>, uri: Uri) -> impl IntoResponse {
18→    let path = uri.path();
19→    if path.starts_with("/assets/") || path.contains('.') {
20→        return (StatusCode::NOT_FOUND, "not found").into_response();
21→    }
22→
23→    let onboarded = onboarding_completed(&state.gateway).await;
24→    if should_redirect_to_onboarding(path, onboarded) {
25→        return Redirect::to("/onboarding").into_response();
26→    }
27→    render_spa_template(&state.gateway, SpaTemplate::Index).await
28→}
29→
30→pub async fn onboarding_handler(State(state): State<AppState>) -> impl IntoResponse {
