	localProvider,
	sysInfo,
	localModels,
	selectedBackend,
	setSelectedBackend,
	apiKey,
	setApiKey,
	endpoint,
	setEndpoint,
	model,
	setModel,
	saving,
	savingModels,
	error,
	validationResult,
	onStartConfigure,
	onCancelConfigure,
	onSaveKey,
	onToggleModel,
