/// been configured yet.  Instructs the user to set up authentication from a
/// local connection or the CLI, preventing any remote party from claiming the
/// instance (#350).
#[cfg(feature = "web-ui")]
const SETUP_REQUIRED_HTML: &str = r#"<!DOCTYPE html>
