use std::{net::SocketAddr, sync::Arc};

use axum::{
    extract::{ConnectInfo, FromRef, FromRequestParts},
    http::{HeaderMap, StatusCode, request::Parts},
};

#[cfg(any(feature = "web-ui", feature = "vault"))]
use axum::{
    extract::State,
    middleware::Next,
    response::{IntoResponse, Json, Redirect},
};
